const crypto = require('crypto');
const item = $input.first().json;
const h = item.headers ?? {};
const ts = parseInt(h['x-managecall-timestamp'] ?? '0', 10);
if (Math.abs(Date.now() / 1000 - ts) > 300) throw new Error('timestamp_expired');
const body = typeof item.body === 'string' ? item.body : JSON.stringify(item.body ?? {});
const expected = 'sha256=' + crypto.createHmac('sha256', $env.MANAGECALL_WEBHOOK_SECRET).update(`${ts}.${body}`).digest('hex');
if (!crypto.timingSafeEqual(Buffer.from(expected), Buffer.from(h['x-managecall-signature-256'] ?? ''))) throw new Error('invalid_signature');
return $input.all();

const payload = $input.first().json.body ?? {};
const data = payload.data ?? {};
const disposition = String(data.disposition ?? '').toLowerCase();
const missed = disposition.includes('no_answer') || disposition.includes('missed') || disposition.includes('busy');
if (!missed) return [];
return [{ json: { tenant_id: payload.tenant_id, event_id: payload.event_id, call_id: data.call_id, from_number: data.from_number, to_number: data.to_number, occurred_at: payload.timestamp } }];
